import React, { useState, useEffect, useRef, useCallback } from 'react';
import './App.css';

const API = 'http://localhost:3001';
const USER_ID = (() => {
  let id = localStorage.getItem('tuneai_uid');
  if (!id) { id = Math.random().toString(36).slice(2); localStorage.setItem('tuneai_uid', id); }
  return 'tuneai_' + id;
})();

const MOODS = ['Energetic','Chill','Happy','Melancholic','Focus','Late Night','Workout','Party'];

export default function App() {
  const [query, setQuery]           = useState('');
  const [mood, setMood]             = useState('');
  const [genre, setGenre]           = useState('');
  const [playlist, setPlaylist]     = useState(null);
  const [loading, setLoading]       = useState(false);
  const [error, setError]           = useState('');
  const [playing, setPlaying]       = useState(null);
  const [pinnedIds, setPinnedIds]   = useState([]);
  const [didYouMean, setDidYouMean] = useState(null);
  const [showHistory, setShowHistory] = useState(false);
  const [history, setHistory]       = useState([]);
  const [toast, setToast]           = useState('');
  const searchTimer = useRef(null);
  const toastTimer  = useRef(null);

  useEffect(() => { loadPins(); }, []);

  async function loadPins() {
    try {
      const res  = await fetch(`${API}/pins?userId=${USER_ID}`);
      const data = await res.json();
      setPinnedIds((data || []).map(s => s.id));
    } catch {}
  }

  function showToast(msg) {
    setToast(msg);
    clearTimeout(toastTimer.current);
    toastTimer.current = setTimeout(() => setToast(''), 2500);
  }

  // ── Search with debounce ──────────────────────────────────────────────
  function handleQueryChange(val) {
    setQuery(val);
    clearTimeout(searchTimer.current);
    if (!val.trim()) { setDidYouMean(null); return; }
    searchTimer.current = setTimeout(async () => {
      try {
        const res  = await fetch(`${API}/search?q=${encodeURIComponent(val)}`);
        const data = await res.json();
        if (data.didYouMean) setDidYouMean(data.didYouMean);
        else setDidYouMean(null);
      } catch {}
    }, 500);
  }

  // ── Generate playlist ─────────────────────────────────────────────────
  const generate = useCallback(async () => {
    setLoading(true);
    setError('');
    setPlaying(null);
    try {
      const res  = await fetch(`${API}/generate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          userId: USER_ID,
          mood,
          genre,
          artists: query,
          songs:   '',
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Failed to generate');
      setPlaylist(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [mood, genre, query]);

  // ── Pin / Unpin ───────────────────────────────────────────────────────
  async function togglePin(song) {
    const isPinned = pinnedIds.includes(song.id || song.title);
    const songId   = song.id || song.title;
    if (isPinned) {
      await fetch(`${API}/pin`, {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: USER_ID, songId }),
      });
      setPinnedIds(prev => prev.filter(id => id !== songId));
      showToast('Removed from saved');
    } else {
      await fetch(`${API}/pin`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          userId: USER_ID,
          song: { id: songId, title: song.title, artist: song.artist },
        }),
      });
      setPinnedIds(prev => [...prev, songId]);
      showToast('❤️ Saved!');
    }
  }

  // ── Load history ──────────────────────────────────────────────────────
  async function loadHistory() {
    try {
      const res  = await fetch(`${API}/playlists?userId=${USER_ID}`);
      const data = await res.json();
      setHistory(Array.isArray(data) ? data : []);
      setShowHistory(true);
    } catch { setHistory([]); setShowHistory(true); }
  }

  return (
    <div className="app">

      {/* ── NAV ── */}
      <nav className="nav">
        <div className="brand">
          <div className="brand-dot" />
          <span className="brand-name">Tune<span className="accent">AI</span></span>
        </div>
        <div className="nav-right">
          {pinnedIds.length > 0 && (
            <span style={{fontSize:12,color:'#e91e8c',fontWeight:600}}>
              ❤️ {pinnedIds.length} saved
            </span>
          )}
          <button className="btn-ghost" onClick={loadHistory}>My Playlists</button>
        </div>
      </nav>

      {/* ── HERO ── */}
      <div className="hero">
        <div className="eyebrow">AI-powered music curation</div>
        <h1>Your taste,<br /><em>reimagined.</em></h1>
        <p className="tagline">
          Search by song name, lyrics, or even typos — AI finds the right song and builds your perfect playlist.
        </p>
      </div>

      {/* ── SMART SEARCH ── */}
      <div className="search-wrap">
        <div className="search-box">
          <span className="search-icon">🔍</span>
          <input
            className="search-input"
            type="text"
            placeholder='Try "tum hi ho", "jo bhi main kehna" or "arijt singh"...'
            value={query}
            onChange={e => handleQueryChange(e.target.value)}
          />
          {query && (
            <button className="search-clear" onClick={() => { setQuery(''); setDidYouMean(null); }}>✕</button>
          )}
        </div>
        {didYouMean && (
          <div className="did-you-mean">
            <span>🤖 Did you mean:</span>
            <strong>{didYouMean}</strong>
            <button className="dym-btn" onClick={() => { setQuery(didYouMean); setDidYouMean(null); }}>
              Use this
            </button>
          </div>
        )}
      </div>

      {/* ── MOOD CHIPS ── */}
      <div className="mood-wrap">
        <span className="mood-label">Pick your mood</span>
        <div className="mood-chips">
          {MOODS.map(m => (
            <button
              key={m}
              className={`mood-chip${mood === m.toLowerCase() ? ' active' : ''}`}
              onClick={() => setMood(mood === m.toLowerCase() ? '' : m.toLowerCase())}
            >{m}</button>
          ))}
        </div>
      </div>

      {/* ── GENRE + EXTRA ── */}
      <div className="form-grid">
        <div className="field">
          <label>Genre lean</label>
          <select value={genre} onChange={e => setGenre(e.target.value)}>
            <option value="">Any genre</option>
            <option value="indie">Indie / Alt</option>
            <option value="hip-hop">Hip-Hop</option>
            <option value="electronic">Electronic</option>
            <option value="r&b">R&B / Soul</option>
            <option value="pop">Pop</option>
            <option value="jazz">Jazz</option>
            <option value="rock">Rock</option>
            <option value="bollywood">Bollywood</option>
            <option value="classical">Classical</option>
          </select>
        </div>
        <div className="field">
          <label>Favourite Artists</label>
          <input
            type="text"
            className="form-input"
            placeholder="e.g. Arijit Singh, The Weeknd"
            value={query}
            onChange={e => handleQueryChange(e.target.value)}
          />
        </div>
      </div>

      {/* ── GENERATE BUTTON ── */}
      <button
        className={`gen-btn${loading ? ' busy' : ''}`}
        onClick={generate}
        disabled={loading}
      >
        {loading
          ? <span className="dots">Analysing your taste<span>.</span><span>.</span><span>.</span></span>
          : '✨ Generate My Playlist'
        }
      </button>

      {error && <div className="error-box">❌ {error}</div>}

      {/* ── PLAYLIST RESULT ── */}
      {playlist && (
        <>
          <div className="divider"><span>your playlist</span></div>
          {pinnedIds.length > 0 && (
            <div className="pinned-banner">❤️ {pinnedIds.length} songs saved</div>
          )}
          <div className="playlist-card">
            <div className="pcard-head">
              <div className="pcover">
                <svg width="28" height="28" viewBox="0 0 24 24"><path d="M12 3v10.55A4 4 0 1014 17V7h4V3h-6z"/></svg>
              </div>
              <div className="pinfo">
                <h2>{playlist.title}</h2>
                <p>{playlist.description}</p>
              </div>
              <div className="pbtns">
                <button className="pbtn pbtn-green" onClick={generate}>Regenerate</button>
                <button className="pbtn pbtn-outline" onClick={() => setPlaylist(null)}>Clear</button>
              </div>
            </div>
            <div className="tracklist">
              {(playlist.songs || []).map((song, i) => {
                const songId  = song.id || song.title;
                const isPinned = pinnedIds.includes(songId);
                return (
                  <div
                    key={i}
                    className={`track${playing === i ? ' playing' : ''}`}
                    onClick={() => setPlaying(playing === i ? null : i)}
                  >
                    <div className="tnum">{playing === i ? '▶' : i + 1}</div>
                    <div className="tthumb">
                      <svg width="16" height="16" viewBox="0 0 24 24" fill={playing === i ? '#1db954' : '#888'}>
                        <path d="M9 19c0 1.1-.9 2-2 2s-2-.9-2-2 .9-2 2-2 2 .9 2 2zm11-2c0 1.1-.9 2-2 2s-2-.9-2-2 .9-2 2-2 2 .9 2 2zM9 3v13H7V9l-4 1V8l6-5zm11 0v13h-2V9l-4 1V8l6-5z"/>
                      </svg>
                    </div>
                    <div className="tinfo">
                      <div className="tname">{song.title}</div>
                      <div className="tartist">{song.artist}</div>
                      <div className="twhy">+ {song.reason}</div>
                    </div>
                    <div className="track-right">
                      <button
                        className={`pin-btn${isPinned ? ' pinned' : ''}`}
                        onClick={e => { e.stopPropagation(); togglePin(song); }}
                        title={isPinned ? 'Remove' : 'Save song'}
                      >{isPinned ? '❤️' : '🤍'}</button>
                      <div className="tdur">
                        {playing === i
                          ? <div className="wave"><span/><span/><span/><span/></div>
                          : `${2 + (i % 2)}:${String(10 + (i * 7) % 50).padStart(2, '0')}`
                        }
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </>
      )}

      {/* ── EMPTY STATE ── */}
      {!playlist && !loading && (
        <>
          <div className="divider"><span>your playlist</span></div>
          <div className="empty-state">
            <div className="empty-ring">
              <svg width="28" height="28" viewBox="0 0 24 24"><path d="M12 3v10.55A4 4 0 1014 17V7h4V3h-6z"/></svg>
            </div>
            <p>Search a song or artist above, pick your mood and hit generate.</p>
          </div>
        </>
      )}

      {/* ── HISTORY MODAL ── */}
      {showHistory && (
        <div className="modal-bg" onClick={() => setShowHistory(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-head">
              <h3>My Playlists</h3>
              <button onClick={() => setShowHistory(false)}>✕</button>
            </div>
            {history.length === 0
              ? <p className="modal-empty">No playlists saved yet. Generate your first one!</p>
              : history.map((pl, i) => (
                <div key={i} className="history-item"
                  onClick={() => { setPlaylist(pl); setShowHistory(false); }}>
                  <div className="history-title">{pl.title}</div>
                  <div className="history-meta">
                    {pl.songs?.length || 0} songs · {new Date(pl.createdAt).toLocaleDateString()}
                  </div>
                </div>
              ))
            }
          </div>
        </div>
      )}

      {/* ── TOAST ── */}
      {toast && <div className="toast">{toast}</div>}
    </div>
  );
}
